  animation-delay: -10s;
}

@keyframes glow-float {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(30px, -20px) scale(1.05); }
  66% { transform: translate(-20px, 30px) scale(0.95); }
}

/* ============================================
    TYPOGRAPHY
    ============================================ */
h1, h2, h3, h4, h5, h6 {
  font-weight: var(--weight-extrabold);
  line-height: var(--leading-tight);
  color: var(--text-primary);
  letter-spacing: -0.02em;
}

h1 {
  font-size: clamp(2rem, 4.5vw, 3rem);
  font-weight: var(--weight-black);
  background: linear-gradient(135deg, var(--text-primary) 0%, var(--accent-primary) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: var(--space-4);
}

h2 {
  font-size: clamp(1.5rem, 3vw, 2.25rem);
  margin-bottom: var(--space-6);
}

h3 {
  font-size: clamp(1.25rem, 2.5vw, 1.75rem);
  margin-bottom: var(--space-4);
}

p {
  margin: 0;
  line-height: var(--leading-relaxed);
}

a {
  color: inherit;
  text-decoration: none;
  transition: var(--transition-smooth);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

button,
input,
select,
textarea {
  font: inherit;
  color: inherit;
}

/* ============================================
    ACCESSIBILITY - FOCUS STYLES
    ============================================ */
:focus-visible {
  outline: 2px solid var(--accent-primary);
  outline-offset: 2px;
  border-radius: var(--radius-sm);
}

button:focus-visible,
a:focus-visible {
  outline: 2px solid var(--accent-primary);
  outline-offset: 2px;
}

/* Skip to main content link */
.skip-link {
  position: absolute;
  top: -40px;
  left: 0;
  background: var(--accent-primary);
  color: #fff;
  padding: var(--space-2) var(--space-4);
  z-index: var(--z-tooltip);
  transition: top var(--transition-smooth);
  font-weight: var(--weight-bold);
}

.skip-link:focus {
  top: 0;
}

/* ============================================
     SCROLL REVEAL ANIMATIONS
     ============================================ */
.reveal {
  opacity: 0;
  transform: translateY(30px);
  transition: 
    opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1),
    transform 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  will-change: opacity, transform;
}

.reveal.active {
  opacity: 1;
  transform: translateY(0);
  will-change: auto;
}

.reveal-fade {
  opacity: 0;
  transition: opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  will-change: opacity;
}

.reveal-fade.active {
  opacity: 1;
  will-change: auto;
}

.reveal-scale {
  opacity: 0;
  transform: scale(0.9);
  transition: 
    opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1),
    transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
  will-change: opacity, transform;
}

.reveal-scale.active {
  opacity: 1;
  transform: scale(1);
  will-change: auto;
}

/* ============================================
     FIXES FOR UI ISSUES
     ============================================ */
/* Staggered Animation Delays */
.reveal-delay-1 { transition-delay: 0.1s; }
.reveal-delay-2 { transition-delay: 0.2s; }
.reveal-delay-3 { transition-delay: 0.3s; }
.reveal-delay-4 { transition-delay: 0.4s; }
.reveal-delay-5 { transition-delay: 0.5s; }

/* Page Transition */
.page-transition {
  animation: pageEnter 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}

@keyframes pageEnter {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ============================================
    LAYOUT
    ============================================ */
.page {
  width: min(var(--content-max), calc(100% - var(--space-8)));
  margin: var(--space-6) auto var(--space-11);
}

section[id],
main[id],
footer[id] {
  scroll-margin-top: 100px;
}

.profile-card {
  overflow: hidden;
}

.portfolio-shell {
  overflow: visible;
}

/* ============================================
    PROFILE CARD - PREMIUM LIGHT GLASS DESIGN
    ============================================ */
.profile-cover {
  display: flex;
  align-items: flex-end;
  justify-content: flex-end;
  width: 100%;
  min-height: 320px;
  padding: var(--space-7);
  color: #fff;
  background: url("صور/Pixel Photography logo 3d.png") center / cover no-repeat;
  border: 0;
  cursor: zoom-in;
  position: relative;
  overflow: hidden;
  border-radius: var(--radius-2xl);
}

.profile-main {
  display: grid;
  grid-template-columns: minmax(200px, 240px) 1fr;
  gap: var(--space-7);
  padding: 0 var(--space-8) var(--space-8);
  position: relative;
}

/* Premium Avatar with Gradient Ring */
.avatar-ring {
  position: relative;
  display: grid;
  width: 210px;
  height: 210px;
  margin-top: -105px;
  place-items: center;
  border-radius: 50%;
  padding: 5px;
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary), var(--accent-tertiary));
  box-shadow: 0 0 30px rgba(108, 77, 255, 0.3);
  transition: all var(--transition-bounce);
}

.avatar-ring:hover {
  transform: scale(1.05);
  box-shadow: 0 0 40px rgba(108, 77, 255, 0.5);
}

.avatar-ring:active {
  transform: scale(1.02);
  transition: transform var(--transition-fast);
}

.avatar {
  position: relative;
  display: grid;
  width: 100%;
  height: 100%;
  place-items: center;
  overflow: hidden;
  background: var(--bg-tertiary);
  border: 4px solid #fff;
  border-radius: 50%;
  cursor: zoom-in;
  padding: 0;
  transition: all var(--transition-smooth);
}

.avatar:hover {
  filter: brightness(1.08);
}

.avatar:active {
  transform: scale(0.98);
  transition: transform var(--transition-fast);
}

.avatar img {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.media-open {
  transition: all var(--transition-smooth);
}

.media-open:hover {
  filter: brightness(1.1);
  transform: scale(1.02);
}

/* Profile Info */
.profile-info {
  padding-top: var(--space-7);
}

.profile-line {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--space-5);
  margin-bottom: var(--space-5);
  flex-wrap: wrap;
}

.bio {
  max-width: 700px;
  margin-bottom: var(--space-5);
  color: var(--text-secondary);
  font-size: var(--text-lg);
  line-height: var(--leading-relaxed);
}

/* Profile Title Row */
.profile-title-row {
  display: flex;
  align-items: center;
  gap: var(--space-2);
}

.verified-badge {
  display: inline-grid;
  place-items: center;
  width: 24px;
  height: 24px;
  flex-shrink: 0;
}

.verified-badge svg {
  width: 100%;
  height: 100%;
}

/* Profile Location */
.profile-location {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--text-muted);
  font-size: var(--text-sm);
  font-weight: var(--weight-semibold);
  margin-bottom: var(--space-4);
}

.profile-location svg {
  color: var(--accent-primary);
  flex-shrink: 0;
}

/* Profile Action Buttons */
.profile-actions {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  margin-bottom: var(--space-5);
}

.btn-action {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  padding: var(--space-3) var(--space-5);
  border-radius: var(--radius-lg);
  font-weight: var(--weight-bold);
  font-size: var(--text-sm);
  text-decoration: none;
  transition: all var(--transition-smooth);
  min-height: 50px;
  border: 1px solid transparent;
  position: relative;
  overflow: hidden;
}

.btn-whatsapp {
  background: var(--gradient-cinematic);
  color: #fff;
  box-shadow: 0 4px 15px rgba(108, 77, 255, 0.35);
}

.btn-whatsapp:hover {
  transform: translateY(-3px) scale(1.03);
  box-shadow: 0 8px 25px rgba(108, 77, 255, 0.5);
}

.btn-contact {
  background: #0a0a1a;
  color: #fff;
}

.btn-contact:hover {
  transform: translateY(-3px) scale(1.03);
  box-shadow: 0 8px 25px rgba(10, 10, 26, 0.3);
}

.btn-email {
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  color: var(--text-primary);
  border-color: var(--line-default);
}

.btn-email:hover {
  transform: translateY(-3px) scale(1.03);
  border-color: var(--accent-primary);
  color: var(--accent-primary);
  box-shadow: var(--shadow-lg);
}

/* ============================================
    BUTTONS - PREMIUM BLUE STYLES
    ============================================ */
.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: 1px solid transparent;
  cursor: pointer;
  font-weight: var(--weight-semibold);
  transition: all var(--transition-smooth);
  position: relative;
  overflow: hidden;
}

.button.primary {
  min-height: 52px;
  padding: 0 var(--space-8);
  color: #fff;
  background: linear-gradient(135deg, var(--accent-dark) 0%, var(--accent-primary) 50%, var(--accent-secondary) 100%);
  border-color: transparent;
  border-radius: var(--radius-full);
  box-shadow: 
    0 4px 15px rgba(108, 77, 255, 0.35),
    0 0 0 0 rgba(108, 77, 255, 0.4);
  font-size: var(--text-base);
  letter-spacing: 0.02em;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.button.primary::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 0;
  height: 0;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.3);
  transform: translate(-50%, -50%);
  transition: width 0.6s, height 0.6s;
}

.button.primary:hover::before {
  width: 300px;
  height: 300px;
}

.button.primary:hover {
  transform: translateY(-3px) scale(1.05);
  box-shadow: 
    0 12px 30px rgba(108, 77, 255, 0.5),
    0 0 0 8px rgba(108, 77, 255, 0.15);
  background: linear-gradient(135deg, var(--accent-darker) 0%, var(--accent-dark) 50%, var(--accent-primary) 100%);
}

.button.primary:active {
  transform: translateY(-1px) scale(1.02);
  transition: transform var(--transition-fast);
}

/* ============================================
    PORTFOLIO HEADER & SECTION TITLE
    ============================================ */
.portfolio-header {
  text-align: center;
  margin-bottom: var(--space-8);
  padding: 0 var(--space-4);
}

.portfolio-title {
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  font-weight: var(--weight-black);
  background: linear-gradient(135deg, var(--text-primary) 0%, var(--accent-primary) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: var(--space-2);
  letter-spacing: -0.03em;
}

.portfolio-subtitle {
  color: var(--text-muted);
  font-size: var(--text-base);
  font-weight: var(--weight-medium);
  max-width: 480px;
  margin: 0 auto;
}

/* ============================================
    SERVICES NAVIGATION — Premium Category Cards
    ============================================ */
.services-nav {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-4);
  margin: 0 0 var(--space-10);
  padding: var(--space-2);
  contain: layout style;
}

.service-circle {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-3);
  text-decoration: none;
  color: var(--text-primary);
  font-weight: var(--weight-bold);
  font-size: var(--text-xs);
  transition: all var(--transition-smooth);
  flex: 0 0 auto;
  width: 110px;
  padding: var(--space-4) var(--space-3);
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border: 1.5px solid var(--glass-border);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-sm);
}

.service-circle-icon {
  display: grid;
  width: 52px;
  height: 52px;
  place-items: center;
  background: var(--bg-tertiary);
  border-radius: var(--radius-lg);
  color: var(--accent-primary);
  transition: all var(--transition-bounce);
}

.service-circle:hover,
.service-circle:focus-visible {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
  border-color: var(--accent-light);
}

.service-circle:hover .service-circle-icon,
.service-circle:focus-visible .service-circle-icon {
  background: var(--gradient-cinematic);
  color: #fff;
  transform: scale(1.08);
  box-shadow: 0 8px 20px rgba(108, 77, 255, 0.3);
}

.service-circle:active {
  transform: translateY(-2px);
  transition: transform var(--transition-fast);
}

.service-circle:active .service-circle-icon {
  transform: scale(1.03);
  transition: transform var(--transition-fast);
}

.service-circle.active {
  background: var(--gradient-cinematic);
  border-color: transparent;
  color: #fff;
  box-shadow: 0 8px 25px rgba(108, 77, 255, 0.3);
}

.service-circle.active .service-circle-icon {
  background: rgba(255, 255, 255, 0.2);
  color: #fff;
}

.service-circle-label {
  text-align: center;
  max-width: 90px;
  line-height: var(--leading-snug);
}

/* Categories Toggle */
.categories-toggle-wrap {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin: var(--space-3) 0;
}

.categories-line {
  flex: 1;
  height: 0;
  border-top: 2px dashed var(--line-strong);
}

.categories-toggle {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-5);
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border: 1.5px solid var(--glass-border);
  border-radius: var(--radius-full);
  color: var(--text-secondary);
  font-size: var(--text-sm);
  font-weight: var(--weight-bold);
  cursor: pointer;
  transition: all var(--transition-smooth);
  white-space: nowrap;
}

.categories-toggle:hover {
  border-color: var(--accent-light);
  color: var(--accent-primary);
  box-shadow: var(--shadow-sm);
}

.categories-toggle svg {
  transition: transform var(--transition-smooth);
}

.categories-toggle[aria-expanded="true"] svg {
  transform: rotate(180deg);
}

/* Expanded Categories Container */
.services-nav-expanded {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-4);
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  transition: max-height 400ms ease, opacity 300ms ease, margin 300ms ease;
  margin-top: 0;
}

.services-nav-expanded.open {
  max-height: 500px;
  opacity: 1;
  margin-top: var(--space-3);
}

/* ============================================
    FEATURED PREVIEWS & VIDEO GRID
    ============================================ */
.featured-preview {
  margin-bottom: var(--space-10);
  content-visibility: auto;
  contain-intrinsic-size: auto 400px;
}

.featured-preview-title {
  font-size: var(--text-xl);
  font-weight: var(--weight-extrabold);
  color: var(--text-primary);
  margin-bottom: var(--space-5);
  padding: 0 var(--space-4);
  letter-spacing: -0.02em;
  position: relative;
  padding-right: var(--space-5);
}

.featured-preview-title::before {
  content: '';
  position: absolute;
  right: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 4px;
  height: 24px;
  background: var(--gradient-cinematic);
  border-radius: var(--radius-full);
}

/* Homepage: show only 3 featured videos per category */
#page-home .video-grid .reel-card:nth-child(n+4) {
  display: none;
}

/* Homepage video-grid: always 3 columns */
#page-home .video-grid {
  grid-template-columns: repeat(3, 1fr);
}

/* Search results grid: show all results, use auto-fill */
#page-home #search-results-grid {
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
}

#page-home #search-results-grid .reel-card:nth-child(n+4) {
  display: block;
}

/* ============================================
    VIDEO SEARCH
    ============================================ */
.video-search-wrap {
  max-width: 480px;
  margin: 0 auto var(--space-8);
  padding: 0 var(--space-4);
}

.video-search {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  padding: var(--space-3) var(--space-5);
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border: 1px solid var(--glass-border);
  border-radius: var(--radius-full);
  box-shadow: var(--shadow-md);
  transition: all var(--transition-smooth);
}

.video-search:focus-within {
  border-color: var(--accent-primary);
  box-shadow: 0 0 0 3px rgba(108, 77, 255, 0.15), var(--shadow-lg);
}

.search-icon {
  color: var(--text-muted);
  flex-shrink: 0;
  transition: color var(--transition-smooth);
}

.video-search:focus-within .search-icon {
  color: var(--accent-primary);
}

.video-search-input {
  flex: 1;
  border: none;
  outline: none;
  background: transparent;
  font-size: var(--text-base);
  font-family: inherit;
  color: var(--text-primary);
}

.video-search-input::placeholder {
  color: var(--text-subtle);
}

.video-search-input::-webkit-search-cancel-button {
  -webkit-appearance: none;
}

.video-search-results {
  margin-bottom: var(--space-8);
  padding: 0 var(--space-4);
  content-visibility: auto;
  contain-intrinsic-size: auto 400px;
}

.search-results-count {
  color: var(--text-muted);
  font-size: var(--text-sm);
  font-weight: var(--weight-semibold);
  margin-bottom: var(--space-4);
  padding: 0 var(--space-4);
}

.search-no-results {
  text-align: center;
  color: var(--text-muted);
  font-size: var(--text-lg);
  padding: var(--space-10) 0;
}

/* View All Button */
.view-all-btn {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  margin-top: var(--space-4);
  margin-right: var(--space-4);
  padding: var(--space-2) var(--space-5);
  background: var(--glass-bg);
  backdrop-filter: var(--glass-blur);
  -webkit-backdrop-filter: var(--glass-blur);
  border: 1px solid var(--glass-border);
  border-radius: var(--radius-full);
  color: var(--accent-primary);
  font-weight: var(--weight-bold);
  font-size: var(--text-sm);
  text-decoration: none;
  transition: all var(--transition-smooth);
}

.view-all-btn:hover {
  background: var(--gradient-cinematic);
  border-color: transparent;
  color: #fff;
  transform: translateX(-4px);
  box-shadow: 0 4px 15px rgba(108, 77, 255, 0.35);
}

.view-all-btn:active {
  transform: translateX(-2px);
  transition: transform var(--transition-fast);
}

.video-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: var(--space-5);
  padding: 0 var(--space-4);
  contain: layout style;
}

.video-grid::-webkit-scrollbar {
  display: none;
}

.reel-card {
  position: relative;
  overflow: hidden;
  border-radius: 24px;
  background: var(--bg-tertiary);
  border: 1px solid var(--line-default);
  box-shadow: var(--shadow-lg);
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
  contain: layout paint;
}

/* Premium Hover Animation */
.reel-card:hover {
  transform: translateY(-8px) scale(1.02);
  box-shadow: var(--shadow-2xl);
  border-color: var(--accent-glow-strong);
}

.reel-card:active {
  transform: translateY(-4px) scale(1.01);
  transition: transform var(--transition-fast);
}

/* Video Element */
.reel-card video {
  width: 100%;
  aspect-ratio: 9 / 16;
  object-fit: contain;
  display: block;
  position: relative;
  z-index: 1;
  border-radius: 24px;
  background: var(--bg-tertiary);
}

/* Loading Skeleton */
.reel-card.loading {
  pointer-events: none;
  position: relative;
}

.reel-card.loading::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    90deg,
    rgba(108, 77, 255, 0.04) 0%,
    rgba(108, 77, 255, 0.08) 50%,
    rgba(108, 77, 255, 0.04) 100%
  );
  background-size: 200% 100%;
  animation: shimmer 2s ease-in-out infinite;
  z-index: 5;
  border-radius: inherit;
  will-change: background-position;
}

.reel-card.loading::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--bg-tertiary);
  border-radius: inherit;
  z-index: 0;
}

@keyframes shimmer {
  0% {
    background-position: -200% 0;
  }
  100% {
    background-position: 200% 0;
  }
}

/* Ripple effect for bottom nav clicks */
@keyframes ripple {
  to {
    width: 100px;
    height: 100px;
    opacity: 0;
  }
}

.ripple {
  position: absolute;
  width: 20px;
  height: 20px;
  background: rgba(59, 130, 246, 0.3);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  pointer-events: none;
  animation: ripple 0.6s ease-out;
}

/* Video Controls Styling */
.reel-card video::-webkit-media-controls-panel {
  border-radius: 0 0 24px 24px;
}

/* Firefox Controls */
.reel-card video::-moz-media-controls {
  border-radius: 0 0 24px 24px;
}

/* Video Card Overlays - Premium */
.reel-overlay {
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;
  border-radius: 24px;
  overflow: hidden;
}

/* Category Tag */
.reel-tag {
  position: absolute;
  top: var(--space-3);
  left: var(--space-3);
  padding: var(--space-1) var(--space-3);
  background: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border-radius: var(--radius-full);
  color: #fff;
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  letter-spacing: 0.03em;
  opacity: 0;
  transform: translateY(-8px);
  transition: all var(--transition-smooth);
}

.reel-card:hover .reel-tag {
  opacity: 1;
  transform: translateY(0);
}

/* Play Button Overlay */
.reel-play-btn {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.85);
  width: 56px;
  height: 56px;
  display: grid;
  place-items: center;
  background: rgba(255, 255, 255, 0.92);
  border-radius: 50%;
  color: var(--accent-primary);
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
  opacity: 0;
  transition: all var(--transition-bounce);
}

.reel-card:hover .reel-play-btn {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}

.reel-play-btn svg {
  width: 24px;
  height: 24px;
}

/* Hide play button when video is playing */
.reel-card.playing .reel-play-btn {
  opacity: 0;
  transform: translate(-50%, -50%) scale(0.8);
  pointer-events: none;
}

/* Also hide tag when playing for cleaner look */
.reel-card.playing .reel-tag {
  opacity: 0;
  transform: translateY(-8px);
}

/* Bottom Gradient */
.reel-gradient {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 80px;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.5) 0%, transparent 100%);
  opacity: 0;
  transition: opacity var(--transition-smooth);
  border-radius: 0 0 var(--radius-2xl) var(--radius-2xl);
}

.reel-card:hover .reel-gradient {
  opacity: 1;
}

.reel-card.playing .reel-gradient {
  opacity: 0;
}

/* Touch devices: always show tag and gradient */
@media (hover: none) {
  .reel-tag {
    opacity: 1;
    transform: translateY(0);
  }

  .reel-play-btn {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1);
  }

  .reel-gradient {
    opacity: 1;
  }
}

/* Simplified transitions on mobile touch devices */
@media (hover: none) and (max-width: 768px) {
  .reel-card {
    transition: transform 0.3s ease, box-shadow 0.3s ease;
  }
}

/* ============================================
    PAGE VIEW SYSTEM - SPA NAVIGATION
    ============================================ */
.page-view {
  display: none;
  content-visibility: auto;
  contain-intrinsic-size: auto 500px;
}

