  background: linear-gradient(135deg, var(--accent-dark), var(--accent-primary), var(--accent-secondary));
  color: #fff;
  box-shadow: 
    0 4px 15px rgba(108, 77, 255, 0.4),
    0 0 0 0 rgba(108, 77, 255, 0.4);
}

.nav-link.active::before {
  display: none;
}

.nav-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: var(--space-2) var(--space-6);
  color: #fff;
  text-decoration: none;
  font-weight: var(--weight-bold);
  font-size: var(--text-sm);
  background: linear-gradient(135deg, var(--accent-dark), var(--accent-primary), var(--accent-secondary));
  border-radius: var(--radius-full);
  box-shadow: 
    0 4px 15px rgba(108, 77, 255, 0.4),
    0 0 0 0 rgba(108, 77, 255, 0.4);
  transition: all var(--transition-bounce);
  white-space: nowrap;
}

.nav-cta:hover {
  transform: translateY(-2px);
  box-shadow: 
    0 8px 25px rgba(108, 77, 255, 0.5),
    0 0 0 8px rgba(108, 77, 255, 0.15);
  background: linear-gradient(135deg, var(--accent-darker), var(--accent-dark), var(--accent-primary));
}

/* ============================================
    BOTTOM NAVIGATION - MOBILE
    ============================================ */
.bottom-nav {
  position: fixed;
  bottom: max(var(--space-5), env(safe-area-inset-bottom));
  left: 50%;
  transform: translateX(-50%);
  z-index: var(--z-sticky);
  width: calc(100% - var(--space-8));
  max-width: 500px;
  direction: ltr;
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid rgba(108, 77, 255, 0.08);
  border-radius: var(--radius-full);
  box-shadow: 
    0 20px 60px rgba(108, 77, 255, 0.1),
    0 8px 24px rgba(108, 77, 255, 0.06),
    0 0 0 1px rgba(108, 77, 255, 0.15) inset,
    0 0 30px rgba(108, 77, 255, 0.08);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.bottom-nav:hover {
  box-shadow: 
    0 24px 70px rgba(0, 0, 0, 0.18),
    0 12px 32px rgba(108, 77, 255, 0.1),
    0 0 0 2px rgba(108, 77, 255, 0.25) inset,
    0 0 40px rgba(108, 77, 255, 0.12);
}

.bottom-nav-container {
  display: flex;
  align-items: center;
  justify-content: space-around;
  padding: var(--space-2) var(--space-4);
  gap: var(--space-2);
}

.bottom-nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-1);
  padding: var(--space-2) var(--space-3);
  color: var(--text-muted);
  text-decoration: none;
  font-weight: var(--weight-semibold);
  font-size: var(--text-xs);
  border-radius: var(--radius-lg);
  transition: all var(--transition-smooth);
  position: relative;
  min-width: 60px;
  background: transparent;
  border: none;
  cursor: pointer;
  font-family: inherit;
}

.bottom-nav-item::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(108, 77, 255, 0.12), rgba(79, 125, 255, 0.08));
  border-radius: var(--radius-lg);
  opacity: 0;
  transition: opacity var(--transition-smooth);
}

.bottom-nav-item:hover {
  color: var(--accent-primary);
  transform: translateY(-2px);
}

.bottom-nav-item:hover::before {
  opacity: 1;
}

.bottom-nav-item.active {
  color: var(--accent-primary);
  background: linear-gradient(135deg, rgba(108, 77, 255, 0.15), rgba(79, 125, 255, 0.1));
  box-shadow: 0 4px 12px rgba(108, 77, 255, 0.25);
}

.bottom-nav-item.active::before {
  opacity: 1;
  background: linear-gradient(135deg, rgba(108, 77, 255, 0.2), rgba(79, 125, 255, 0.15));
}

.nav-icon {
  width: 24px;
  height: 24px;
  transition: all var(--transition-bounce);
  position: relative;
  z-index: 1;
}

.bottom-nav-item:hover .nav-icon {
  transform: scale(1.15);
}

.bottom-nav-item.active .nav-icon {
  transform: scale(1.1);
  filter: drop-shadow(0 2px 4px rgba(108, 77, 255, 0.4));
}

.nav-label {
  position: relative;
  z-index: 1;
  font-size: var(--text-xs);
  font-weight: var(--weight-semibold);
  letter-spacing: 0.02em;
  transition: all var(--transition-smooth);
}

/* Tooltip */
.bottom-nav-item[data-tooltip] {
  position: relative;
}

.bottom-nav-item[data-tooltip]::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: calc(100% + 10px);
  left: 50%;
  transform: translateX(-50%) translateY(5px);
  padding: var(--space-2) var(--space-3);
  background: rgba(255, 255, 255, 0.98);
  color: var(--accent-primary);
  font-size: var(--text-xs);
  font-weight: var(--weight-semibold);
  white-space: nowrap;
  border-radius: var(--radius-md);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-smooth);
  pointer-events: none;
  box-shadow: var(--shadow-lg);
  border: 1px solid rgba(108, 77, 255, 0.3);
}

.bottom-nav-item[data-tooltip]::before {
  content: '';
  position: absolute;
  bottom: calc(100% + 4px);
  left: 50%;
  transform: translateX(-50%) translateY(5px);
  width: 0;
  height: 0;
  border-left: 6px solid transparent;
  border-right: 6px solid transparent;
  border-top: 6px solid rgba(255, 255, 255, 0.98);
  opacity: 0;
  visibility: hidden;
  transition: all var(--transition-smooth);
  pointer-events: none;
}

.bottom-nav-item[data-tooltip]:hover::after,
.bottom-nav-item[data-tooltip]:hover::before {
  opacity: 1;
  visibility: visible;
  transform: translateX(-50%) translateY(0);
}

/* ============================================
    MENU PANEL - PREMIUM LIGHT OVERLAY
    ============================================ */
.menu-panel {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: var(--z-modal);
  background: rgba(255, 255, 255, 0.8);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  display: none;
  align-items: center;
  justify-content: center;
  padding: var(--space-5);
  padding-top: max(var(--space-5), env(safe-area-inset-top));
  padding-bottom: max(var(--space-5), env(safe-area-inset-bottom));
  opacity: 0;
  transition: opacity var(--transition-smooth);
}

.menu-panel.active {
  display: flex;
  opacity: 1;
  animation: fadeIn 0.3s ease;
}

.menu-panel-content {
  background: rgba(255, 255, 255, 0.98);
  border: 1px solid rgba(108, 77, 255, 0.08);
  border-radius: var(--radius-2xl);
  padding: var(--space-8) var(--space-6);
  max-width: 400px;
  width: 100%;
  box-shadow: 
    0 24px 80px rgba(108, 77, 255, 0.12),
    0 12px 40px rgba(108, 77, 255, 0.08),
    0 0 60px rgba(108, 77, 255, 0.15);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  position: relative;
  animation: scaleIn 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}

@keyframes scaleIn {
  from {
    transform: scale(0.9);
    opacity: 0;
  }
  to {
    transform: scale(1);
    opacity: 1;
  }
}

.menu-close {
  position: absolute;
  top: var(--space-4);
  left: var(--space-4);
  width: 44px;
  height: 44px;
  display: grid;
  place-items: center;
  background: rgba(108, 77, 255, 0.1);
  border: 1px solid rgba(108, 77, 255, 0.3);
  border-radius: 50%;
  cursor: pointer;
  color: var(--accent-primary);
  transition: all var(--transition-smooth);
}

.menu-close:hover {
  background: rgba(108, 77, 255, 0.2);
  transform: rotate(90deg);
  border-color: var(--accent-primary);
  box-shadow: 0 4px 12px rgba(108, 77, 255, 0.3);
}

.menu-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-4);
  margin-top: var(--space-6);
}

.menu-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--space-3);
  padding: var(--space-5) var(--space-4);
  background: var(--surface);
  border: 1px solid rgba(108, 77, 255, 0.06);
  border-radius: var(--radius-xl);
  color: var(--text-primary);
  text-decoration: none;
  font-weight: var(--weight-bold);
  font-size: var(--text-sm);
  transition: all var(--transition-bounce);
  box-shadow: var(--shadow-md);
  position: relative;
  overflow: hidden;
}

.menu-item::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(108, 77, 255, 0.1), rgba(79, 125, 255, 0.08));
  opacity: 0;
  transition: opacity var(--transition-smooth);
}

.menu-item:hover::before {
  opacity: 1;
}

.menu-item:hover {
  background: var(--surface-strong);
  transform: translateY(-6px);
  box-shadow: 
    var(--shadow-xl),
    0 0 0 1px rgba(108, 77, 255, 0.4),
    0 0 30px rgba(108, 77, 255, 0.2);
  border-color: var(--accent-primary);
  color: var(--accent-primary);
}

.menu-item:active {
  transform: translateY(-3px);
  transition: transform var(--transition-fast);
}

.menu-icon {
  display: grid;
  width: 60px;
  height: 60px;
  place-items: center;
  background: linear-gradient(135deg, rgba(108, 77, 255, 0.15), rgba(79, 125, 255, 0.1));
  border-radius: var(--radius-lg);
  color: var(--accent-primary);
  transition: all var(--transition-bounce);
  box-shadow: var(--shadow-sm);
}

.menu-item:hover .menu-icon {
  background: linear-gradient(135deg, var(--accent-primary), var(--accent-secondary));
  color: #fff;
  transform: scale(1.1);
  box-shadow: 
    0 6px 20px rgba(108, 77, 255, 0.4),
    0 0 0 0 rgba(108, 77, 255, 0.4);
}

.menu-icon.whatsapp {
  background: linear-gradient(135deg, rgba(37, 211, 102, 0.15), rgba(18, 140, 126, 0.1));
  color: #25d366;
}

.menu-item:hover .menu-icon.whatsapp {
  background: linear-gradient(135deg, #25d366, #128c7e);
  color: #fff;
}

.menu-icon.instagram {
  background: linear-gradient(135deg, rgba(245, 133, 41, 0.15), rgba(221, 42, 123, 0.1));
  color: #f58529;
}

.menu-item:hover .menu-icon.instagram {
  background: linear-gradient(135deg, #f58529, #dd2a7b, #8134af);
  color: #fff;
}

.menu-icon.email {
  background: linear-gradient(135deg, rgba(255, 154, 86, 0.15), rgba(241, 90, 36, 0.1));
  color: #ff9a56;
}

.menu-item:hover .menu-icon.email {
  background: linear-gradient(135deg, #ff9a56, #f15a24);
  color: #fff;
}

/* ============================================
    RESPONSIVE DESIGN
    ============================================ */

/* Large Tablets and Small Desktops */
@media (max-width: 1024px) {
  .page,
  .footer {
    width: min(100%, calc(100% - var(--space-6)));
  }

  .profile-main {
    grid-template-columns: 1fr;
    justify-items: center;
    text-align: center;
  }

  .profile-info {
    padding-top: var(--space-5);
  }

  .profile-line {
    flex-direction: column;
    align-items: stretch;
  }

  .services-nav {
    gap: var(--space-3);
  }

  .categories-toggle-wrap {
    gap: var(--space-2);
  }

  .services-nav-expanded {
    gap: var(--space-3);
  }

  .footer-container {
    grid-template-columns: 1fr 1fr;
    gap: var(--space-8);
  }

  .footer-brand {
    grid-column: 1 / -1;
  }
}

/* Tablets */
@media (max-width: 768px) {
  .profile-cover {
    min-height: 260px;
    padding: var(--space-6);
  }

  .profile-main {
    padding: 0 var(--space-5) var(--space-6);
    gap: var(--space-5);
  }

  .avatar-ring {
    width: 170px;
    height: 170px;
    margin-top: -85px;
  }

  .profile-line {
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: var(--space-4);
  }

  .services-nav {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-3);
    padding: var(--space-2);
  }

  .service-circle {
    width: 100%;
    padding: var(--space-3) var(--space-2);
  }

  .service-circle-icon {
    width: 48px;
    height: 48px;
  }

  .service-circle-label {
    font-size: var(--text-xs);
  }

  .services-nav-expanded {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: var(--space-3);
    padding: var(--space-2);
  }

  .services-nav-expanded .service-circle {
    width: 100%;
  }

  /* Homepage: keep 3 columns on tablet */
  #page-home .video-grid {
    grid-template-columns: repeat(3, 1fr);
  }

  /* Category pages: 2 columns on tablet */
  .video-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-4);
    padding: 0 var(--space-4);
  }

  .reel-card {
    border-radius: 20px;
  }

  .reel-card video {
    border-radius: 20px;
  }

  .reel-overlay {
    border-radius: 20px;
  }

  .reel-card video::-webkit-media-controls-panel {
    border-radius: 0 0 20px 20px;
  }

  .reel-card video::-moz-media-controls {
    border-radius: 0 0 20px 20px;
  }

  .footer {
    margin-top: var(--space-8);
    padding: var(--space-4) 0 var(--space-3);
  }

  .footer-container {
    grid-template-columns: 1fr;
    gap: var(--space-4);
    padding: var(--space-4);
  }

  .footer-brand {
    gap: var(--space-2);
  }

  .footer-links {
    flex-direction: row;
    flex-wrap: wrap;
    gap: var(--space-3);
  }

  .footer-link {
    font-size: var(--text-sm);
  }

  .footer-social {
    gap: var(--space-2);
  }

  .footer-bottom {
    flex-direction: row;
    justify-content: space-between;
    gap: var(--space-2);
    text-align: center;
    padding-top: var(--space-3);
    margin-top: var(--space-2);
  }

  /* Mobile Navigation */
  .floating-nav {
    top: var(--space-3);
    width: calc(100% - var(--space-5));
    border-radius: var(--radius-xl);
  }

  .nav-container {
    padding: var(--space-2) var(--space-4);
    gap: var(--space-3);
  }

  .nav-logo {
    font-size: var(--text-base);
  }

  .logo-icon {
    width: 38px;
    height: 38px;
    font-size: var(--text-base);
  }

  .nav-toggle {
    display: flex;
  }

  .nav-menu {
    position: absolute;
    top: calc(100% + var(--space-3));
    left: 0;
    right: 0;
    flex-direction: column;
    background: rgba(255, 255, 255, 0.98);
    border: 1px solid rgba(108, 77, 255, 0.08);
    border-radius: var(--radius-xl);
    padding: var(--space-4);
    gap: var(--space-2);
    box-shadow: 
      0 20px 60px rgba(108, 77, 255, 0.1),
      0 8px 24px rgba(108, 77, 255, 0.06),
      0 0 40px rgba(108, 77, 255, 0.1);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-10px);
    transition: var(--transition-smooth);
  }

  .nav-menu.active {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
  }

  .nav-link,
  .nav-cta {
    width: 100%;
    justify-content: center;
    padding: var(--space-3) var(--space-5);
  }

  .nav-link {
    font-size: var(--text-base);
  }

  .nav-cta {
    margin-top: var(--space-2);
    padding: var(--space-3) var(--space-5);
    font-size: var(--text-base);
  }

  /* Ensure no horizontal scroll on page level */
  .profile-card,
  .page,
  .footer-container {
    overflow-x: hidden;
  }

  .nav-menu {
    max-height: 80vh;
    overflow-y: auto;
  }

  /* Bottom nav visible on all devices */
  .bottom-nav {
    bottom: var(--space-4);
  }

  .btn-action {
    min-height: 44px;
    padding: var(--space-2) var(--space-3);
    font-size: var(--text-xs);
  }
}

