@media (max-width: 540px) {
  /* Page Layout - Prevent horizontal scroll */
  .page {
    width: 100%;
    max-width: 100%;
    margin: var(--space-2) auto var(--space-6);
    padding: 0;
    overflow-x: hidden;
  }

  .profile-card {
    overflow-x: hidden;
    width: 100%;
  }

  /* Profile Section */
