    padding: var(--space-3) 0 var(--space-2);
  }

  .footer-container {
    padding: var(--space-3);
    gap: var(--space-3);
    border-radius: var(--radius-xl);
  }

  .footer-brand {
    gap: var(--space-1);
  }

  .footer-logo {
    font-size: var(--text-sm);
    gap: var(--space-2);
  }

  .footer-logo .logo-icon {
