  .image-modal {
    padding: var(--space-3);
  }

  .modal-close {
    top: var(--space-2);
    right: var(--space-2);
    min-height: 44px;
    padding: 0 var(--space-4);
    font-size: var(--text-sm);
    min-width: 44px;
  }

  /* Sub-pages - Mobile */
  .sub-page-section {
    width: calc(100% - var(--space-4));
    margin: var(--space-4) auto;
  }

  .sub-page-heading {
    font-size: clamp(1.5rem, 5vw, 2rem);
  }

  .sub-page-subtitle {
    font-size: var(--text-sm);
    margin-bottom: var(--space-5);
  }

  .models-grid,
  .buyer-grid,
  .equipment-grid {
    grid-template-columns: 1fr;
    gap: var(--space-3);
  }

  .model-card,
  .buyer-card,
  .equipment-card {
    border-radius: var(--radius-xl);
  }

  .model-body,
  .buyer-body,
  .equipment-body {
    padding: var(--space-3);
    gap: var(--space-2);
  }

  .model-name,
  .buyer-campaign,
  .equipment-name {
    font-size: var(--text-base);
  }

  .model-attributes {
    grid-template-columns: 1fr 1fr;
    gap: var(--space-2);
  }

  .model-book-btn {
    min-height: 44px;
    font-size: var(--text-sm);
  }

  .buyer-result {
    font-size: var(--text-base);
    padding: var(--space-2);
  }

  /* Show bottom nav on mobile */
  .bottom-nav {
    display: block;
    bottom: max(var(--space-3), env(safe-area-inset-bottom));
    width: calc(100% - var(--space-4));
    max-width: 100%;
    border-radius: var(--radius-full);
    padding: 0;
  }

  .bottom-nav-container {
    padding: var(--space-2) var(--space-3);
    gap: var(--space-1);
  }

  .bottom-nav-item {
    padding: var(--space-1) var(--space-1);
    min-width: 44px;
    gap: var(--space-1);
  }

  .nav-icon {
    width: 20px;
    height: 20px;
  }

  .nav-label {
    font-size: 10px;
  }

  .menu-panel-content {
    padding: var(--space-6) var(--space-4);
    max-width: calc(100% - var(--space-8));
    border-radius: var(--radius-xl);
  }

  .menu-grid {
    grid-template-columns: 1fr;
    gap: var(--space-3);
    margin-top: var(--space-5);
  }

  .menu-item {
    flex-direction: row;
    padding: var(--space-4);
    border-radius: var(--radius-lg);
    gap: var(--space-4);
  }

  .menu-icon {
    width: 50px;
    height: 50px;
    border-radius: var(--radius-md);
  }

  .menu-close {
    top: var(--space-3);
    left: var(--space-3);
    width: 40px;
    height: 40px;
  }

  /* Hide floating nav on mobile */
  .floating-nav {
    display: none;
  }

  /* Prevent horizontal scroll */
  body {
    overflow-x: hidden;
  }

  /* Space for fixed bottom nav */
  .footer {
    padding-bottom: max(var(--space-12), env(safe-area-inset-bottom));
  }
}

/* Very Small Screens */
@media (max-width: 380px) {
  .profile-main {
    padding: 0 var(--space-3) var(--space-4);
  }

  .avatar-ring {
    width: 100px;
    height: 100px;
    margin-top: -50px;
  }

  .services-nav {
    gap: var(--space-2);
    padding: var(--space-2) var(--space-3);
  }

  .service-circle {
    width: 85px;
    padding: var(--space-3) var(--space-2);
    gap: var(--space-2);
  }

  .service-circle-icon {
    width: 40px;
    height: 40px;
  }

  .service-circle-label {
    font-size: 9px;
  }

  .services-nav-expanded {
    gap: var(--space-2);
    padding: 0 var(--space-3);
  }

  .services-nav-expanded .service-circle {
    width: 85px;
  }

  /* Homepage: keep 3 columns even on very small screens */
  #page-home .video-grid {
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-1);
  }

  .video-grid {
    gap: var(--space-2);
  }

  .reel-card {
    border-radius: 16px;
  }

  .reel-card video {
    border-radius: 16px;
  }

  .reel-overlay {
    border-radius: 16px;
  }

  .bottom-nav-container {
    padding: var(--space-1);
    gap: 1px;
  }

  .bottom-nav-item {
    padding: var(--space-1);
    min-width: 40px;
  }

  .nav-icon {
    width: 18px;
    height: 18px;
  }

  .nav-label {
    font-size: 9px;
  }
}

/* Landscape Mode on Mobile */
@media (max-height: 500px) and (orientation: landscape) {
  .profile-cover {
    min-height: 140px;
  }

  .avatar-ring {
    width: 100px;
    height: 100px;
    margin-top: -50px;
  }

  .profile-info {
    padding-top: var(--space-3);
  }

  .floating-nav {
    top: var(--space-2);
  }

  .bottom-nav {
    bottom: var(--space-2);
  }
}

/* ============================================
    PERFORMANCE OPTIMIZATIONS
    ============================================ */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .reveal {
    opacity: 1;
    transform: none;
  }

  .reveal-fade {
    opacity: 1;
  }

  .reveal-scale {
    opacity: 1;
    transform: none;
  }
}

/* GPU Acceleration for smooth animations */
.reel-card,
.button,
.service-circle,
.nav-link,
.social-link,
.avatar,
.menu-item,
.bottom-nav-item {
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
  perspective: 1000px;
  -webkit-perspective: 1000px;
}

/* Optimize animations for mobile */
@media (max-width: 768px) {
  .reveal {
    transform: translateY(20px);
    transition: 
      opacity 0.6s cubic-bezier(0.4, 0, 0.2, 1),
      transform 0.6s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .reel-card:hover {
    transform: translateY(-4px);
  }

  .button.primary:hover {
    transform: translateY(-2px) scale(1.03);
  }
}

/* ============================================
    PRINT STYLES
    ============================================ */
@media print {
  .floating-nav,
  .image-modal,
  .bottom-nav,
  .menu-panel,
  .cinematic-viewer,
  .vo-modal {
    display: none !important;
  }

  body {
    background: white;
    color: black;
  }

  .profile-card,
  .portfolio-shell {
    box-shadow: none;
    border: 1px solid #ccc;
  }

  .reveal,
  .reveal-fade,
  .reveal-scale {
    opacity: 1;
    transform: none;
  }
}

/* ============================================
    CINEMATIC FULLSCREEN VIEWER
    ============================================ */
.cinematic-viewer {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: none;
  align-items: center;
  justify-content: center;
  padding: var(--space-5);
  padding-top: max(var(--space-5), env(safe-area-inset-top));
  padding-bottom: max(var(--space-5), env(safe-area-inset-bottom));
}

.cinematic-viewer.active {
  display: flex;
  animation: cv-fade-in 0.4s ease;
}

@keyframes cv-fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

.cv-backdrop {
  position: absolute;
  inset: 0;
  background: rgba(5, 5, 15, 0.97);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.cv-close {
  position: absolute;
  top: max(var(--space-5), env(safe-area-inset-top));
  right: var(--space-5);
  width: 48px;
  height: 48px;
  display: grid;
  place-items: center;
  background: rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 50%;
  cursor: pointer;
  color: #fff;
  transition: all var(--transition-smooth);
  z-index: 10;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.cv-close:hover {
  background: rgba(255, 255, 255, 0.2);
  transform: rotate(90deg) scale(1.05);
}

.cv-nav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  width: 52px;
  height: 52px;
  display: grid;
  place-items: center;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 50%;
  cursor: pointer;
  color: #fff;
  transition: all var(--transition-smooth);
  z-index: 10;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.cv-prev { left: var(--space-5); }
.cv-next { right: var(--space-5); }

.cv-nav:hover {
  background: var(--gradient-cinematic);
  border-color: transparent;
  transform: translateY(-50%) scale(1.1);
  box-shadow: 0 4px 20px rgba(108, 77, 255, 0.5);
}

.cv-content {
  position: relative;
  z-index: 5;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-4);
  max-width: 500px;
  width: 100%;
  animation: cv-scale-in 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
}

@keyframes cv-scale-in {
  from { transform: scale(0.9); opacity: 0; }
  to { transform: scale(1); opacity: 1; }
}

.cv-video-wrapper {
  width: 100%;
  max-height: 80vh;
  border-radius: var(--radius-2xl);
  overflow: hidden;
  box-shadow: 0 25px 60px rgba(0, 0, 0, 0.5), 0 0 0 1px rgba(108, 77, 255, 0.2);
  background: #000;
}

.cv-video-wrapper video {
  width: 100%;
  height: auto;
  max-height: 80vh;
  object-fit: contain;
  display: block;
  border-radius: var(--radius-2xl);
}

.cv-info {
  text-align: center;
  color: #fff;
}

.cv-tag {
  display: inline-block;
  padding: var(--space-1) var(--space-3);
  background: rgba(108, 77, 255, 0.3);
  border: 1px solid rgba(108, 77, 255, 0.5);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  color: #c4b5ff;
  margin-bottom: var(--space-2);
}

.cv-title {
  font-size: var(--text-xl);
  font-weight: var(--weight-extrabold);
  color: #fff;
  margin: 0;
}

.cv-duration {
  font-size: var(--text-sm);
  color: rgba(255, 255, 255, 0.5);
  margin: 0;
}

/* Cinematic Viewer Responsive */
@media (max-width: 768px) {
  .cv-nav {
    width: 44px;
    height: 44px;
  }

  .cv-prev { left: var(--space-2); }
  .cv-next { right: var(--space-2); }

  .cv-content {
    max-width: 100%;
  }

  .cv-video-wrapper {
    max-height: 70vh;
  }
}

@media (max-width: 540px) {
  .cv-close {
    top: var(--space-3);
    right: var(--space-3);
    width: 40px;
    height: 40px;
  }

  .cv-nav {
    width: 40px;
    height: 40px;
  }

  .cv-video-wrapper video {
    max-height: 65vh;
  }
}

/* ============================================
    VOICE OVER SECTION - PREMIUM CARDS & PLAYER
    ============================================ */

/* Hero */
.voiceover-hero {
  text-align: center;
  margin-bottom: var(--space-8);
}

.voiceover-hero-icon {
  width: 80px;
  height: 80px;
  margin: 0 auto var(--space-4);
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, var(--accent-dark), var(--accent-primary), var(--accent-secondary));
  border-radius: 50%;
  color: #fff;
  box-shadow:
    0 4px 20px rgba(108, 77, 255, 0.4),
    0 0 0 6px rgba(108, 77, 255, 0.12);
  transition: transform var(--transition-bounce);
}

.voiceover-hero-icon:hover {
  transform: scale(1.08);
}

/* Grid */
.voiceover-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: var(--space-6);
  content-visibility: auto;
  contain-intrinsic-size: auto 600px;
}

/* Cards */
.vo-card {
  display: flex;
  flex-direction: column;
  background: var(--surface-elevated);
  border: 1px solid var(--line-default);
  border-radius: var(--radius-2xl);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  transition: all var(--transition-smooth);
  cursor: pointer;
  outline: none;
  contain: layout paint;
}

.vo-card:hover,
.vo-card:focus-visible {
  transform: translateY(-6px);
  box-shadow: var(--shadow-2xl);
  border-color: var(--accent-primary);
}

.vo-card:active {
  transform: translateY(-3px);
  transition: transform var(--transition-fast);
}

/* Card Cover */
.vo-card-cover {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: linear-gradient(135deg, var(--accent-light), rgba(79, 125, 255, 0.04));
  overflow: hidden;
  position: relative;
}

.vo-card-cover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform var(--transition-slow);
}

.vo-card:hover .vo-card-cover img {
  transform: scale(1.05);
}

.vo-card-cover img[src=""],
.vo-card-cover img:not([src]) {
  opacity: 0;
}

/* Play Overlay */
.vo-card-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(to top, rgba(0, 0, 0, 0.45) 0%, transparent 50%);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity var(--transition-smooth);
}

.vo-card:hover .vo-card-overlay,
.vo-card:focus-visible .vo-card-overlay {
  opacity: 1;
}

.vo-card-play {
  width: 56px;
  height: 56px;
  display: grid;
  place-items: center;
  background: rgba(108, 77, 255, 0.92);
  border: 2px solid #fff;
  border-radius: 50%;
  color: #fff;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  box-shadow: 0 4px 20px rgba(108, 77, 255, 0.5);
  transform: scale(0.8);
  transition: transform var(--transition-bounce);
}

.vo-card:hover .vo-card-play {
  transform: scale(1);
}

/* Card Body */
.vo-card-body {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  padding: var(--space-4) var(--space-5) var(--space-5);
}

.vo-card-title {
  font-size: var(--text-lg);
  font-weight: var(--weight-extrabold);
  color: var(--text-primary);
  margin: 0;
}

.vo-card-meta {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  flex-wrap: wrap;
}

.vo-card-category {
  display: inline-flex;
  align-items: center;
  padding: var(--space-1) var(--space-3);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  background: var(--accent-light);
  color: var(--accent-primary);
}

.vo-card-duration {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  padding: var(--space-1) var(--space-3);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  background: var(--bg-tertiary);
  color: var(--text-muted);
}

.vo-card-duration::before {
  content: '';
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-subtle);
}

.vo-card-desc {
  font-size: var(--text-sm);
  color: var(--text-secondary);
  line-height: var(--leading-relaxed);
  margin: 0;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* Empty State */
.voiceover-empty {
  text-align: center;
  padding: var(--space-12) var(--space-4);
}

.voiceover-empty-icon {
  width: 80px;
  height: 80px;
  margin: 0 auto var(--space-5);
  display: grid;
  place-items: center;
  background: var(--accent-light);
  border-radius: 50%;
  color: var(--accent-primary);
  animation: vo-float 3s ease-in-out infinite;
}

@keyframes vo-float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-8px); }
}

.voiceover-empty-text {
  color: var(--text-muted);
  font-size: var(--text-lg);
  font-weight: var(--weight-semibold);
}

/* Touch devices: always show play overlay */
@media (hover: none) {
  .vo-card-overlay {
    opacity: 1;
    background: linear-gradient(to top, rgba(0, 0, 0, 0.3) 0%, transparent 60%);
  }
  .vo-card-play {
    transform: scale(1);
  }
}

/* ============================================
    VOICE OVER MODAL - PREMIUM PLAYER
    ============================================ */

.vo-modal {
  position: fixed;
  inset: 0;
  z-index: var(--z-modal);
  display: none;
  align-items: center;
  justify-content: center;
  padding: var(--space-5);
  padding-top: max(var(--space-5), env(safe-area-inset-top));
  padding-bottom: max(var(--space-5), env(safe-area-inset-bottom));
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}

.vo-modal.active {
  display: flex;
  animation: fadeIn 0.3s ease;
}

.vo-modal-overlay {
  position: absolute;
  inset: 0;
  background: transparent;
}

.vo-modal-content {
  position: relative;
  background: var(--surface-elevated);
  border: 1px solid var(--line-default);
  border-radius: var(--radius-2xl);
  padding: var(--space-6);
  max-width: 560px;
  width: 100%;
  max-height: calc(100vh - var(--space-10));
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
  box-shadow: var(--shadow-2xl);
  animation: scaleIn 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.vo-modal-close {
  position: absolute;
  top: var(--space-4);
  right: var(--space-4);
  width: 40px;
  height: 40px;
  display: grid;
  place-items: center;
  background: var(--accent-light);
  border: 1px solid rgba(108, 77, 255, 0.3);
  border-radius: 50%;
  cursor: pointer;
  color: var(--accent-primary);
  transition: all var(--transition-smooth);
  z-index: 2;
}

.vo-modal-close:hover {
  background: rgba(108, 77, 255, 0.2);
  transform: rotate(90deg);
  border-color: var(--accent-primary);
  box-shadow: 0 4px 12px rgba(108, 77, 255, 0.3);
}

/* Modal Body */
.vo-modal-body {
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

/* Cover Image */
.vo-cover-wrapper {
  width: 160px;
  height: 160px;
  margin: 0 auto;
  border-radius: var(--radius-2xl);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  background: linear-gradient(135deg, var(--accent-light), rgba(79, 125, 255, 0.04));
  position: relative;
}

.vo-cover {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.vo-cover[src=""],
.vo-cover:not([src]) {
  opacity: 0;
}

/* Info */
.vo-info {
  text-align: center;
}

.vo-title {
  font-size: var(--text-xl);
  font-weight: var(--weight-extrabold);
  color: var(--text-primary);
  margin: 0 0 var(--space-2);
}

.vo-meta {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2);
  margin-bottom: var(--space-2);
  flex-wrap: wrap;
}

.vo-category {
  display: inline-flex;
  align-items: center;
  padding: var(--space-1) var(--space-3);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  background: var(--accent-light);
  color: var(--accent-primary);
}

.vo-duration {
  display: inline-flex;
  align-items: center;
  gap: var(--space-1);
  padding: var(--space-1) var(--space-3);
  border-radius: var(--radius-full);
  font-size: var(--text-xs);
  font-weight: var(--weight-bold);
  background: var(--bg-tertiary);
  color: var(--text-muted);
}

.vo-duration::before {
  content: '';
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-subtle);
}

.vo-description {
  font-size: var(--text-sm);
  color: var(--text-secondary);
  line-height: var(--leading-relaxed);
  margin: 0;
}

/* Player */
.vo-player {
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
}

/* Waveform */
.vo-waveform-container {
  position: relative;
  width: 100%;
  height: 72px;
  background: var(--bg-tertiary);
  border-radius: var(--radius-lg);
  overflow: hidden;
  cursor: pointer;
}

.vo-waveform {
  width: 100%;
  height: 100%;
  display: block;
}

.vo-loading-spinner {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 36px;
  height: 36px;
  margin: -18px 0 0 -18px;
  border: 3px solid var(--accent-light);
  border-top-color: var(--accent-primary);
  border-radius: 50%;
  animation: vo-spin 0.8s linear infinite;
}

@keyframes vo-spin {
  to { transform: rotate(360deg); }
}

/* Time Display */
.vo-time {
  display: flex;
  justify-content: space-between;
  font-size: var(--text-xs);
  font-weight: var(--weight-semibold);
  color: var(--text-muted);
  font-variant-numeric: tabular-nums;
}

/* Controls */
.vo-controls {
